//SOUND_BEGIN
//SOUND_BEGIN
// =========================================================================
// Title: Tie-Dye Sonification (Harmonic Drone)
// Note: Versione ammorbidita. Utilizza intervalli di quinta giusta (110Hz e 165Hz)
// e sottomultipli per una modulazione FM molto più dolce.
// =========================================================================

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f*f*(3.0-2.0*f);

    float a = fract(sin(dot(i, vec2(12.9898, 78.233))) * 43758.5453);
    float b = fract(sin(dot(i + vec2(1.0, 0.0), vec2(12.9898, 78.233))) * 43758.5453);
    float c = fract(sin(dot(i + vec2(0.0, 1.0), vec2(12.9898, 78.233))) * 43758.5453);
    float d = fract(sin(dot(i + vec2(1.0, 1.0), vec2(12.9898, 78.233))) * 43758.5453);
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

vec2 mainSound( int samp, float time ) {
    // Frequenze armoniche: 110Hz (La) e 165Hz (Mi, una quinta giusta sopra)
    float freqL = 110.0; 
    float freqR = 165.0; 

    // Modulazione molto più dolce (usiamo 55.0Hz, che è l'ottava bassa di 110Hz)
    // Questo garantisce che le distorsioni siano intonate con la nota principale
    float t = time * 0.2;
    float modL = sin(6.28318 * 55.0 * time + t) * 0.8; 
    float modR = cos(6.28318 * 55.0 * time - t) * 0.8;

    // Generazione dei toni principali (onde sinusoidali modificate dolcemente)
    float toneL = sin(6.28318 * freqL * time + modL);
    float toneR = sin(6.28318 * freqR * time + modR);

    // Aggiungiamo un'ottava superiore morbida per dare un po' di "luce" al suono
    toneL += sin(6.28318 * 220.0 * time) * 0.25;
    toneR += sin(6.28318 * 330.0 * time) * 0.25;

    // Rumore di fondo abbassato di frequenza e di volume (solo per dare un po' di respiro)
    float nL = noise(vec2(time * 300.0, time * 100.0)) - 0.5;
    float nR = noise(vec2(time * 100.0, time * 320.0)) - 0.5;

    // Mix finale: diamo priorità ai toni armonici e scaliamo tutto per non superare 1.0
    // (evitando così il fastidioso effetto "onda quadra" del clamp)
    vec2 audio = vec2(toneL, toneR) * 0.6 + vec2(nL, nR) * 0.03;

    // Inviluppo per ammorbidire l'attacco iniziale
    float env = smoothstep(0.0, 2.0, time) * (0.8 + 0.2 * sin(time * 0.5));

    return clamp(audio * env, -1.0, 1.0);
}
//SOUND_END

//SOUND_END

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f*f*(3.0-2.0*f); // Smoothstep interpolation

    float a = fract(sin(dot(i, vec2(12.9898, 78.233))) * 43758.5453);
    float b = fract(sin(dot(i + vec2(1, 0), vec2(12.9898, 78.233))) * 43758.5453);
    float c = fract(sin(dot(i + vec2(0, 1), vec2(12.9898, 78.233))) * 43758.5453);
    float d = fract(sin(dot(i + vec2(1, 1), vec2(12.9898, 78.233))) * 43758.5453);
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

mat2 rot(float a) {
    float c = cos(a), s = sin(a);
    return mat2(c,-s,s,c);
}

vec3 pal(float t) {
    return vec3(.5,.4,.5)+vec3(.5,.2,.5)
        *cos(6.28318*(vec3(1./2.,1./3.,5) * t + vec3(0,.54,0)-iTime*.4));
}

float getFreq(float f) {
    return texture(iChannel0, vec2(f,.25)).x;
}

vec3 tiedie(vec2 uv, float f) {
    float t = iTime * 0.4;
    float fft = getFreq(.001)*.35 - getFreq(.99)*.2;

    uv *= rot(t*.9);
    float amp = .3;
    float a = atan(uv.y+amp*sin(t),uv.x+amp*cos(t));

    uv.x += amp * cos(sin(a*f+t)*fft + t);
    uv.y += amp * sin(cos(a*f+t)*fft + t);

    return pal((1.-exp(-length(uv)*2.))*3.+.3);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = 1.*(fragCoord - 0.5 * iResolution.xy) / iResolution.y;
    vec3 col = tiedie(uv, 4.);
    vec3 col2 = tiedie(uv, 220.);

    col = mix(col, col2, .2);
    col = pow(col, vec3(2));
    col += vec3(.4,.4,.1)*(exp(-length(uv+.2*vec2(cos(iTime*.4),sin(iTime*.4)))*1.));
    col += .05 * (noise(uv * 400.)-.5);

    fragColor = vec4(col, 1.0);
}
